  1	import { type FC, useEffect, useRef } from 'react';
  2	import { Controller, type FieldPath, type FieldValues, useWatch } from 'react-hook-form';
  3	
  4	import FormGroupWithErrorText from '@components/common/FormGroupWithErrorText';
  5	import { HelpIconPopover } from '@components/common/HelpIconPopover/HelpIconPopover';
  6	import ProjectSelect from '@components/common/ProjectSelect/ProjectSelect';
  7	import { MenuToggleStatus, Stack, StackItem } from '@patternfly/react-core';
  8	import { isEmpty } from '@utils/helpers';
  9	import { useDefaultProject } from '@utils/hooks/useDefaultProject';
 10	import useWatchProjectNames from '@utils/hooks/useWatchProjectNames';
 11	import { useForkliftTranslation } from '@utils/i18n';
 12	import { isSystemNamespace } from '@utils/namespaces';
 13	
 14	import { useCreatePlanFormContext } from '../../hooks/useCreatePlanFormContext';
 15	
 16	import { GeneralFormFieldId, generalFormFieldLabels } from './constants';
 17	
 18	type PlanProjectFieldProps = {
 19	  testId?: string;
 20	};
 21	
 22	const PlanProjectField: FC<PlanProjectFieldProps> = ({ testId = 'plan-project-select' }) => {
 23	  const { t } = useForkliftTranslation();
 24	  const {
 25	    control,
 26	    formState: { errors },
 27	    setValue,
 28	  } = useCreatePlanFormContext();
 29	
 30	  const [projectNames] = useWatchProjectNames();
 31	
 32	  const hasProjects = !isEmpty(projectNames);
 33	  const defaultProject = useDefaultProject(projectNames);
 34	  const hasSetInitialDefault = useRef(false);
 35	  const showDefaultProjects =
 36	    useWatch({ control, name: GeneralFormFieldId.ShowDefaultProjects }) ?? false;
 37	
 38	  const [planProject, sourceProvider, targetProvider, targetProject] = useWatch({
 39	    control,
 40	    name: [
 41	      GeneralFormFieldId.PlanProject,
 42	      GeneralFormFieldId.SourceProvider,
 43	      GeneralFormFieldId.TargetProvider,
 44	      GeneralFormFieldId.TargetProject,
 45	    ],
 46	  });
 47	
 48	  useEffect(() => {
 49	    if (defaultProject && hasProjects && !hasSetInitialDefault.current && isEmpty(planProject)) {
 50	      setValue(GeneralFormFieldId.PlanProject, defaultProject);
 51	      setValue(GeneralFormFieldId.ShowDefaultProjects, isSystemNamespace(defaultProject));
 52	
 53	      hasSetInitialDefault.current = true;
 54	    }
 55	  }, [defaultProject, setValue, planProject, hasProjects]);
 56	
 57	  return (
 58	    <FormGroupWithErrorText
 59	      isRequired
 60	      fieldId={GeneralFormFieldId.PlanProject}
 61	      label={generalFormFieldLabels[GeneralFormFieldId.PlanProject]}
 62	      labelIcon={
 63	        <HelpIconPopover>
 64	          <Stack hasGutter>
 65	            <StackItem>
 66	              {t(
 67	                'The project that your migration plan will be created in. Only projects with providers in them can be selected.',
 68	              )}
 69	            </StackItem>
 70	            <StackItem>
 71	              {t('Projects, also known as namespaces, separate resources within clusters.')}
 72	            </StackItem>
 73	          </Stack>
 74	        </HelpIconPopover>
 75	      }
 76	    >
 77	      <Controller
 78	        name={GeneralFormFieldId.PlanProject}
 79	        control={control}
 80	        render={({ field }) => (
 81	          <ProjectSelect
 82	            testId={testId}
 83	            showDefaultProjects={showDefaultProjects}
 84	            setShowDefaultProjects={(value) => {
 85	              setValue(GeneralFormFieldId.ShowDefaultProjects, value);
 86	            }}
 87	            placeholder={t('Select plan project')}
 88	            id={GeneralFormFieldId.PlanProject}
 89	            projectNames={projectNames}
 90	            value={field.value}
 91	            onChange={(value) => {
 92	              field.onChange(value);
 93	
 94	              if (sourceProvider) {
 95	                setValue<FieldPath<FieldValues>>(GeneralFormFieldId.SourceProvider, '', {
 96	                  shouldValidate: true,
 97	                });
 98	              }
 99	              if (targetProvider) {
100	                setValue<FieldPath<FieldValues>>(GeneralFormFieldId.TargetProvider, '', {
101	                  shouldValidate: true,
102	                });
103	              }
104	              if (targetProject) {
105	                setValue(GeneralFormFieldId.TargetProject, '', { shouldValidate: true });
106	              }
107	            }}
108	            toggleProps={{
109	              id: 'plan-project-select',
110	              status: errors[GeneralFormFieldId.PlanProject] && MenuToggleStatus.danger,
111	            }}
112	          />
113	        )}
114	        rules={{ required: t('Plan project is required.') }}
115	      />
116	    </FormGroupWithErrorText>
117	  );
118	};
119	
120	export default PlanProjectField;

